{
    "level": "A1–B1",
    "intro": "У цьому розділі зібрано теми, які допомагають правильно працювати з <strong>іменниками</strong>, <strong>артиклями</strong> та <strong>вираженням кількості</strong> в англійській.",
    "rules": [
        {
            "label": "Nouns",
            "color": "emerald",
            "text": "<strong>Форми іменників</strong> — plural nouns, countable / uncountable distinction та partitives.",
            "example": "child → children / a piece of advice"
        },
        {
            "label": "Articles",
            "color": "blue",
            "text": "<strong>Артиклі</strong> — a / an / the, zero article, geographical names та generic reference.",
            "example": "a book / the book / Ø books"
        },
        {
            "label": "Quantity",
            "color": "amber",
            "text": "<strong>Кількість</strong> — quantifiers і означники на кшталт no / none / neither / either.",
            "example": "many books / little time / no money"
        }
    ]
}

{
    "title": "Що входить до категорії",
    "intro": "Поточний контент групується навколо трьох підтем:",
    "items": [
        {
            "label": "NOUN FORMS",
            "title": "Форми іменників",
            "subtitle": "Plural nouns, countable / uncountable nouns і partitives."
        },
        {
            "label": "ARTICLES",
            "title": "Система артиклів",
            "subtitle": "Articles, zero article, geographical names і generic reference."
        },
        {
            "label": "QUANTITY",
            "title": "Слова кількості",
            "subtitle": "Quantifiers та no / none / neither / either без окремого винесення Some / Any у цю категорію."
        }
    ]
}

{
    "title": "Коли відкривати цей розділ",
    "sections": [
        {
            "label": "Форма іменника",
            "color": "emerald",
            "description": "Коли потрібно вибрати singular чи plural або зрозуміти, чи іменник countable / uncountable.",
            "examples": [
                {
                    "en": "one child / two children",
                    "ua": "форма іменника"
                },
                {
                    "en": "much information / many ideas",
                    "ua": "тип іменника впливає на grammar choices"
                }
            ]
        },
        {
            "label": "Артикль",
            "color": "blue",
            "description": "Коли треба вирішити, чи ставити <strong>a / an / the</strong>, чи обрати <strong>zero article</strong>.",
            "examples": [
                {
                    "en": "a city / the city / Ø cities",
                    "ua": "артикль залежить від значення й контексту"
                }
            ]
        },
        {
            "label": "Кількість",
            "color": "amber",
            "description": "Коли потрібно підібрати correct determiner або quantifier: <strong>many, much, few, little, no, none, neither, either</strong>.",
            "examples": [
                {
                    "en": "many books / little time / neither answer",
                    "ua": "вибір залежить від типу noun і значення"
                }
            ]
        }
    ]
}

{
    "title": "Сторінки цієї категорії",
    "items": [
        {
            "label": "Plural Nouns — Множина іменників",
            "current": false
        },
        {
            "label": "Countable / Uncountable Nouns — Злічувані й незлічувані",
            "current": false
        },
        {
            "label": "Articles — A / An / The",
            "current": false
        },
        {
            "label": "Zero Article — Нульовий артикль",
            "current": false
        },
        {
            "label": "Quantifiers — much, many, few, little",
            "current": false
        },
        {
            "label": "Partitives — a piece of, a cup of...",
            "current": false
        },
        {
            "label": "No / None / Neither / Either",
            "current": false
        },
        {
            "label": "Articles with Geographical Names — Географічні назви",
            "current": false
        },
        {
            "label": "Generic Reference — Узагальнення",
            "current": false
        }
    ]
}
